import React from "react";
import styleContacts from "./Contacts.module.css";

const Contacts = () => {
  return (
    <div className={styleContacts.container}>
      <div className={styleContacts.container__comment}>
        <textarea className={styleContacts.container__comment_text}></textarea>
        <button className={styleContacts.container__comment_but}>
          comment
        </button>
      </div>
    </div>
  );
};

export default Contacts;
